#!/bin/bash
set -o pipefail

global_var=""
etlbatchid=$1

if [ $# -ne 1 ]
then
  echo -e "Parameters incorrect: expected parameters for variable etlbatchid\n"
  exit 1
fi


bq_run()
{
	QUERY=$1 
	
	jobID="evo_bi_citi_script7_load-"`date '+%Y%m%d%H%M%S%3N'`

echo -e "\n****************** Query To Execute: ${QUERY} ******************\n"
echo -e "\n****************** Command To Execute: bq query --use_legacy_sql=FALSE ${QUERY} ******************\n"

dry_run_output=`bq query --use_legacy_sql=FALSE --dry_run "${QUERY}"`

if [ $? -eq 0 ]
then
	echo -e "\n****************** $dry_run_output ******************\n"
	
	execution_output=`bq query --job_id=$jobID --use_legacy_sql=FALSE "${QUERY}"`
	
	if [ $? -eq 0 ]
	then
		echo -e "\n****************** Query Ran Successfully ******************\n"
		
		number_of_rows_affected=`bq show --format=prettyjson -j $jobID | grep "numDmlAffectedRows" | head -n 1 | cut -d':' -f2 |sed 's/[\", ]//g'`
		echo "Number Of Rows Affected: $number_of_rows_affected"
		global_var="$number_of_rows_affected "

	else
		echo -ne "{\\\"jobid\\\" : \\\"$jobID\\\",\\\"error\\\" : \\\"$execution_output\\\"}"|tr -d '\n'|tr "'"		"*"
		exit 2
	fi
else
	echo -e "\n****************** Query Validation Failed.... Cause: $dry_run_output ******************\n"
	exit 1
fi
}


Query1="TRUNCATE TABLE transformed_evo_sensitive.tmp_stg_vol_log_detail_citi_banamex_mx; TRUNCATE TABLE transformed_evo.tmp_stg_mid_platform_citi_banamex_mx; TRUNCATE TABLE transformed_evo_sensitive.tmp_stg_vol_log_detail_activity_citi_banamex_mx; TRUNCATE TABLE transformed_evo_sensitive.tmp_stg_vol_log_detail_activity_tnp_citi_banamex_mx; TRUNCATE TABLE transformed_evo_sensitive.tmp_vol_exchange_detail_citi_banamex_mx;"


Query2="INSERT INTO transformed_evo_sensitive.tmp_stg_vol_log_detail_citi_banamex_mx SELECT   CAST(${etlbatchid} AS STRING) AS etlbatchid,   current_date() AS etl_batch_date, generate_uuid() AS tmp_stg_vol_log_detail_citi_banamex_mx_sk, current_timestamp AS create_date_time, current_timestamp AS update_date_time, LT.d_id_merchant, TRIM(ds_platform) AS d_plataforma, TRIM(ds_processor_group) AS procesador_grupo, SAFE_CAST(d_access_channel AS INTEGER) AS d_access_channel, SAFE_CAST(EXTRACT(year FROM d_date_iso_transaction) AS INTEGER) AS year, SAFE_CAST(EXTRACT(month FROM d_date_iso_transaction) AS INTEGER) AS month, TRIM(d_account_cardholder), TRIM(d_authorization_number) AS d_number_authorization, d_amount_transaction, TRIM(d_code_response_transaction), TRIM(d_pos_entry_mode), SAFE_CAST(d_id_dispatcher AS integer) AS d_id_dispatcher, TRIM(d_bin_issuer), TRIM(d_code_result_on2), d_type_message, d_type_transaction_on2, d_date_iso_transaction, TRIM(d_id_form_factor), TRIM(d_id_electronic_commerce), TRIM(d_number_terminal_transaction), TRIM(d_serial_device), TRIM(d_logical_network), TRIM(t.ks_platform), kn_acquirer_intern FROM consumption_evo_sensitive.vw_log_transactional_multiacquirer AS LT LEFT JOIN transformed_evo.d_dispatcher_la T ON IFNULL(TRIM(T.ks_dispatcher),'') = IFNULL(TRIM(CAST(LT.d_id_dispatcher as string)),'') WHERE d_date_iso_transaction>= date_sub(current_date(), INTERVAL 365 day) GROUP BY lt.d_id_merchant, ds_platform, ds_processor_group, d_access_channel, year, month, d_account_cardholder, d_authorization_number, d_amount_transaction, d_code_response_transaction, d_pos_entry_mode, d_id_dispatcher, d_bin_issuer, d_code_result_on2, d_type_message, d_type_transaction_on2, d_date_iso_transaction, d_id_form_factor, d_id_electronic_commerce, d_number_terminal_transaction, d_serial_device, d_logical_network, t.ks_platform, kn_acquirer_intern;"


Query3="TRUNCATE TABLE transformed_evo.tmp_stg_mid_platform_citi_banamex_mx; INSERT INTO transformed_evo.tmp_stg_mid_platform_citi_banamex_mx SELECT CAST(${etlbatchid} AS STRING) AS etlbatchid, current_date() AS etl_batch_date, generate_uuid() AS tmp_stg_mid_platform_citi_banamex_mx_sk, current_timestamp AS create_date_time, current_timestamp AS update_date_time, d_id_merchant, TRIM(ks_platform), ds_source, dn_source_order FROM ( SELECT d_id_merchant, TRIM(d_plataforma) AS ks_platform, 'Onboarding' AS ds_source, 4 AS dn_source_order FROM ( SELECT kn_merchant AS d_id_merchant, '010' AS d_plataforma FROM consumption_evo_bi.f_onboarding_mx WHERE dn_iacepta_flag = -1 GROUP BY kn_merchant UNION DISTINCT SELECT kn_merchant AS d_id_merchant, '020' AS d_plataforma FROM consumption_evo_bi.f_onboarding_mx WHERE ds_tpv_model IS NOT NULL GROUP BY kn_merchant UNION DISTINCT SELECT kn_merchant AS d_id_merchant, '030' AS d_plataforma FROM consumption_evo_bi.f_onboarding_mx WHERE TRIM(ds_plan_negocio_flag) = 'SI' GROUP BY kn_merchant UNION DISTINCT SELECT kn_merchant AS d_id_merchant, '110' AS d_plataforma FROM consumption_evo_bi.f_onboarding_mx WHERE dn_orion_flag = -1 GROUP BY kn_merchant UNION DISTINCT SELECT kn_merchant AS d_id_merchant, '050' AS d_plataforma FROM consumption_evo_bi.f_onboarding_mx WHERE dn_call_center_flag = -1 GROUP BY kn_merchant UNION DISTINCT SELECT kn_merchant AS d_id_merchant, '040' AS d_plataforma FROM consumption_evo_bi.f_onboarding_mx WHERE dn_cab_flag = -1 GROUP BY kn_merchant UNION DISTINCT SELECT kn_merchant AS d_id_merchant, '150' AS d_plataforma FROM consumption_evo_bi.f_onboarding_mx WHERE dn_total_access_flag = -1 GROUP BY kn_merchant UNION DISTINCT SELECT kn_merchant AS d_id_merchant, '120' AS d_plataforma FROM consumption_evo_bi.f_onboarding_mx WHERE dn_interred_pura_flag = -1 GROUP BY kn_merchant UNION DISTINCT SELECT kn_merchant AS d_id_merchant, '073' AS d_plataforma FROM consumption_evo_bi.f_onboarding_mx WHERE dn_ecomm_flag = -1 GROUP BY kn_merchant UNION DISTINCT SELECT kn_merchant AS d_id_merchant, '120' AS d_plataforma FROM consumption_evo_bi.f_onboarding_mx WHERE dn_interred_central_flag = -1 GROUP BY kn_merchant UNION DISTINCT SELECT kn_merchant AS d_id_merchant, '080' AS d_plataforma FROM consumption_evo_bi.f_onboarding_mx WHERE dn_ecomm_global_flag = -1 GROUP BY kn_merchant UNION DISTINCT SELECT kn_merchant AS d_id_merchant, '060' AS d_plataforma FROM consumption_evo_bi.f_onboarding_mx WHERE dn_click_y_paga_flag = -1 GROUP BY kn_merchant UNION DISTINCT SELECT kn_merchant AS d_id_merchant, '100' AS d_plataforma FROM consumption_evo_bi.f_onboarding_mx WHERE TRIM(ds_product) = 'Avender' GROUP BY kn_merchant ) onboarding WHERE d_id_merchant IS NOT NULL AND d_id_merchant <> 0 GROUP BY d_id_merchant, d_plataforma UNION DISTINCT SELECT d_id_merchant, TRIM(d_plataforma) AS ks_platform, 'Implant' AS ds_source, 3 AS dn_source_order FROM ( SELECT kn_merchant AS d_id_merchant, TRIM(ks_platform) AS d_plataforma FROM consumption_evo_bi.f_implant_mx GROUP BY kn_merchant, ks_platform ) implant WHERE d_id_merchant IS NOT NULL AND TRIM(d_plataforma) <> '000' AND d_id_merchant <> -1 GROUP BY d_id_merchant, d_plataforma UNION DISTINCT SELECT d_id_merchant, TRIM(d_plataforma) AS ks_platform, 'Activity' AS ds_source, 2 AS dn_source_order FROM ( SELECT d_id_merchant, CASE WHEN ks_platform IS NULL THEN CASE TRIM(SAFE_CAST(d_access_channel AS string)) WHEN '02' THEN '084' WHEN '08' THEN '052' WHEN '09' THEN '084' ELSE '020' END ELSE ks_platform END AS d_plataforma FROM transformed_evo_sensitive.tmp_stg_vol_log_detail_citi_banamex_mx GROUP BY d_id_merchant, CASE WHEN ks_platform IS NULL THEN CASE trim(SAFE_CAST(d_access_channel AS string)) WHEN '02' THEN '084' WHEN '08' THEN '052' WHEN '09' THEN '084' ELSE '020' END ELSE ks_platform END ) activity WHERE d_id_merchant IS NOT NULL AND TRIM(d_plataforma) <> '000' GROUP BY d_id_merchant, d_plataforma ) total;"


Query4="TRUNCATE TABLE transformed_evo.stg_mid_platform_citi_banamex_mx; INSERT transformed_evo.stg_mid_platform_citi_banamex_mx ( etlbatchid, etl_batch_date, stg_mid_platform_citi_banamex_mx_sk, create_date_time, update_date_time, d_id_merchant, ks_platform, ds_source, dn_source_order) SELECT CAST(${etlbatchid} AS STRING) AS etlbatchid, CURRENT_DATE() AS etl_batch_date, GENERATE_UUID() AS stg_mid_platform_citi_banamex_mx_sk, CURRENT_TIMESTAMP() AS create_date_time, CURRENT_TIMESTAMP() AS update_date_time, d_id_merchant, TRIM(ks_platform), TRIM(ds_source), dn_source_order FROM ( SELECT d_id_merchant, ks_platform, ds_source, dn_source_order FROM transformed_evo.tmp_stg_mid_platform_citi_banamex_mx UNION DISTINCT SELECT D_ID_MERCHANT, KS_PLATFORM, DS_SOURCE, DN_SOURCE_ORDER FROM ( SELECT D_ID_MERCHANT, KS_PLATFORM, 'ActivityTNP' AS DS_SOURCE, 1 AS DN_SOURCE_ORDER FROM ( SELECT D_ID_MERCHANT, KS_PLATFORM FROM ( SELECT LOG.D_ID_MERCHANT, MIDS.KS_PLATFORM_CONCAT, DCNPR.KN_RULE, DCNPR.DS_DISPATCHER_GROUP_PROCESSOR, DCNPR.DS_LOG_ACCESS_CHANNEL, DCNPR.DS_CNP_GROUP, DCNPR.KS_PLATFORM_ORIGIN, DCNPR.KS_PLATFORM FROM ( SELECT LT.D_ID_MERCHANT, PROCESADOR_GRUPO, D_ACCESS_CHANNEL FROM ( SELECT D_ID_MERCHANT, D_PLATAFORMA AS DS_PLATFORM, PROCESADOR_GRUPO, D_ACCESS_CHANNEL FROM transformed_evo_sensitive.tmp_stg_vol_log_detail_citi_banamex_mx WHERE EXTRACT(YEAR FROM (D_DATE_ISO_TRANSACTION)) >= 2019 AND D_PLATAFORMA IS NOT NULL AND D_PLATAFORMA <> '' GROUP BY D_ID_MERCHANT, D_PLATAFORMA, PROCESADOR_GRUPO, D_ACCESS_CHANNEL ) AS LT ) LOG LEFT JOIN ( SELECT D_ID_MERCHANT, RTRIM( MAX(CASE RNO WHEN 1 THEN KS_PLATFORM ELSE '' END) || ',' || MAX(CASE RNO WHEN 2 THEN KS_PLATFORM ELSE '' END) || ',' || MAX(CASE RNO WHEN 3 THEN KS_PLATFORM ELSE '' END) || ',' || MAX(CASE RNO WHEN 4 THEN KS_PLATFORM ELSE '' END) || ',' || MAX(CASE RNO WHEN 5 THEN KS_PLATFORM ELSE '' END) || ',' || MAX(CASE RNO WHEN 6 THEN KS_PLATFORM ELSE '' END), ',') AS KS_PLATFORM_CONCAT FROM ( SELECT D_ID_MERCHANT, KS_PLATFORM, ROW_NUMBER() OVER ( PARTITION BY D_ID_MERCHANT ORDER BY KS_PLATFORM ) AS RNO FROM ( SELECT D_ID_MERCHANT, SAFE_CAST(KS_PLATFORM AS STRING) AS KS_PLATFORM FROM transformed_evo.tmp_stg_mid_platform_citi_banamex_mx WHERE DN_SOURCE_ORDER = 3 GROUP BY D_ID_MERCHANT, SAFE_CAST(KS_PLATFORM AS STRING) ) Plataforma GROUP BY D_ID_MERCHANT, KS_PLATFORM ) MID_PLATFORM_CONCAT GROUP BY D_ID_MERCHANT ) MIDS ON MIDS.D_ID_MERCHANT = LOG.D_ID_MERCHANT LEFT JOIN transformed_evo.d_card_not_present_transaction_rules_la DCNPR ON LOG.PROCESADOR_GRUPO = DCNPR.DS_DISPATCHER_GROUP_PROCESSOR AND CAST(LOG.D_ACCESS_CHANNEL AS STRING) = DCNPR.DS_LOG_ACCESS_CHANNEL AND INSTR(MIDS.KS_PLATFORM_CONCAT, DCNPR.KS_PLATFORM_ORIGIN) > 0 WHERE DCNPR.KN_RULE IN (7, 8, 9, 10, 11, 23) UNION DISTINCT SELECT LOG.D_ID_MERCHANT, MIDS.KS_PLATFORM_CONCAT, DCNPR.KN_RULE, DCNPR.DS_DISPATCHER_GROUP_PROCESSOR, DCNPR.DS_LOG_ACCESS_CHANNEL, DCNPR.DS_CNP_GROUP, DCNPR.KS_PLATFORM_ORIGIN, DCNPR.KS_PLATFORM FROM ( SELECT LT.D_ID_MERCHANT, PROCESADOR_GRUPO, D_ACCESS_CHANNEL FROM ( SELECT D_ID_MERCHANT, D_PLATAFORMA AS DS_PLATFORM, PROCESADOR_GRUPO, D_ACCESS_CHANNEL FROM transformed_evo_sensitive.tmp_stg_vol_log_detail_citi_banamex_mx WHERE EXTRACT(YEAR FROM (D_DATE_ISO_TRANSACTION)) >= 2019 AND D_PLATAFORMA IS NOT NULL AND D_PLATAFORMA <> '' GROUP BY D_ID_MERCHANT, D_PLATAFORMA, PROCESADOR_GRUPO, D_ACCESS_CHANNEL ) AS LT ) LOG LEFT JOIN ( SELECT D_ID_MERCHANT, RTRIM( MAX(CASE RNO WHEN 1 THEN KS_PLATFORM ELSE '' END) || ',' || MAX(CASE RNO WHEN 2 THEN KS_PLATFORM ELSE '' END) || ',' || MAX(CASE RNO WHEN 3 THEN KS_PLATFORM ELSE '' END) || ',' || MAX(CASE RNO WHEN 4 THEN KS_PLATFORM ELSE '' END) || ',' || MAX(CASE RNO WHEN 5 THEN KS_PLATFORM ELSE '' END) || ',' || MAX(CASE RNO WHEN 6 THEN KS_PLATFORM ELSE '' END), ',') AS KS_PLATFORM_CONCAT FROM ( SELECT D_ID_MERCHANT, KS_PLATFORM, ROW_NUMBER() OVER ( PARTITION BY D_ID_MERCHANT ORDER BY KS_PLATFORM ) AS RNO FROM ( SELECT D_ID_MERCHANT, SAFE_CAST(KS_PLATFORM AS STRING) AS KS_PLATFORM FROM transformed_evo.tmp_stg_mid_platform_citi_banamex_mx WHERE DN_SOURCE_ORDER = 3 GROUP BY D_ID_MERCHANT, SAFE_CAST(KS_PLATFORM AS STRING) ) Plataforma GROUP BY D_ID_MERCHANT, KS_PLATFORM ) MID_PLATFORM_CONCAT GROUP BY D_ID_MERCHANT ) MIDS ON MIDS.D_ID_MERCHANT = LOG.D_ID_MERCHANT LEFT JOIN transformed_evo.d_card_not_present_transaction_rules_la DCNPR ON LOG.PROCESADOR_GRUPO = DCNPR.DS_DISPATCHER_GROUP_PROCESSOR AND CAST(LOG.D_ACCESS_CHANNEL AS STRING) = DCNPR.DS_LOG_ACCESS_CHANNEL WHERE DCNPR.KN_RULE NOT IN (7, 8, 9, 10, 11, 23) ) GROUPS1 GROUP BY D_ID_MERCHANT, KS_PLATFORM ) ACTIVITY WHERE D_ID_MERCHANT IS NOT NULL AND KS_PLATFORM <> '000' GROUP BY D_ID_MERCHANT, KS_PLATFORM ) Total );"


Query5="DELETE FROM transformed_evo.stg_mid_platform_citi_banamex_mx SMP WHERE SMP.KS_PLATFORM IN (  SELECT  SMP.KS_PLATFORM FROM  transformed_evo.stg_mid_platform_citi_banamex_mx SMP  LEFT JOIN consumption_evo_bi.d_merchant_mx DM ON DM.KN_MERCHANT=SMP.D_ID_MERCHANT  LEFT JOIN transformed_evo.d_platform_gateway_cl DPG ON DPG.KS_PLATFORM=SMP.KS_PLATFORM   WHERE  DPG.DS_PLATFORM_FAMILY='110'   AND (DS_SOURCE='Implant' OR DS_SOURCE='Onboarding') ) AND SMP.D_ID_MERCHANT IN (SELECT D_ID_MERCHANT,   FROM  transformed_evo.stg_mid_platform_citi_banamex_mx SMP  LEFT JOIN consumption_evo_bi.d_merchant_mx DM ON DM.KN_MERCHANT=SMP.D_ID_MERCHANT  LEFT JOIN transformed_evo.d_platform_gateway_cl DPG ON DPG.KS_PLATFORM=SMP.KS_PLATFORM   WHERE  DPG.DS_PLATFORM_FAMILY='110'   AND (DS_SOURCE='Implant' OR DS_SOURCE='Onboarding') ) AND (SMP.DS_SOURCE='Implant' );"


Query6="DELETE FROM transformed_evo.stg_mid_platform_citi_banamex_mx SMP WHERE SMP.KS_PLATFORM IN (  SELECT  SMP.KS_PLATFORM FROM  transformed_evo.stg_mid_platform_citi_banamex_mx SMP  LEFT JOIN consumption_evo_bi.d_merchant_mx DM ON DM.KN_MERCHANT=SMP.D_ID_MERCHANT  LEFT JOIN transformed_evo.d_platform_gateway_cl DPG ON DPG.KS_PLATFORM=SMP.KS_PLATFORM   WHERE  DPG.DS_PLATFORM_FAMILY='110'   AND (DS_SOURCE='Implant' OR DS_SOURCE='Onboarding') ) AND SMP.D_ID_MERCHANT IN (SELECT D_ID_MERCHANT,   FROM  transformed_evo.stg_mid_platform_citi_banamex_mx SMP  LEFT JOIN consumption_evo_bi.d_merchant_mx DM ON DM.KN_MERCHANT=SMP.D_ID_MERCHANT  LEFT JOIN transformed_evo.d_platform_gateway_cl DPG ON DPG.KS_PLATFORM=SMP.KS_PLATFORM   WHERE  DPG.DS_PLATFORM_FAMILY='110'   AND (DS_SOURCE='Implant' OR DS_SOURCE='Onboarding') ) AND ( SMP.DS_SOURCE='Onboarding' );"


Query7="TRUNCATE TABLE consumption_evo_bi.f_merchant_platform_citi_banamex_mx; INSERT INTO consumption_evo_bi.f_merchant_platform_citi_banamex_mx ( etlbatchid, etl_batch_date, f_merchant_platform_citi_banamex_mx_sk, kn_merchant, ks_platform, ds_platform_concat, ds_platform_concat_num, dn_source_order_concat, ds_platform_concat_campaign, ds_platform_concat_campaign_num, dn_source_order_concat_campaign) SELECT CAST(${etlbatchid} AS STRING) AS etlbatchid, CURRENT_DATE() AS etl_batch_date, GENERATE_UUID() AS f_merchant_platform_citi_banamex_mx_sk, SAFE_CAST(ONE.D_ID_MERCHANT AS INTEGER) AS KN_MERCHANT, TRIM(ONE.KS_PLATFORM), TRIM(CONCAT.KS_PLATFORM_CONCAT) AS DS_PLATFORM_CONCAT, CONCAT.KS_PLATFORM_CONCAT_NUM AS DS_PLATFORM_CONCAT_NUM, TRIM(CONCAT.DN_SOURCE_ORDER_CONCAT), TRIM(CONCAT_TOTAL.KS_PLATFORM_CONCAT_TOTAL) AS DS_PLATFORM_CONCAT_CAMPAIGN, TRIM(SAFE_CAST(CONCAT_TOTAL.KS_PLATFORM_CONCAT_NUM_TOTAL AS STRING)) AS DS_PLATFORM_CONCAT_CAMPAIGN_NUM, TRIM(CONCAT_TOTAL.DN_SOURCE_ORDER_CONCAT_TOTAL) AS DN_SOURCE_ORDER_CONCAT_CAMPAIGN FROM ( SELECT D_ID_MERCHANT, KS_PLATFORM FROM ( SELECT SMP.D_ID_MERCHANT, SMP.KS_PLATFORM, SMP.DS_SOURCE, SMP.DN_SOURCE_ORDER, ROW_NUMBER() OVER ( PARTITION BY SMP.D_ID_MERCHANT ORDER BY SMP.DN_SOURCE_ORDER ASC, DPG.DN_PLATFORM_HIERARCHY_ORDER ASC ) AS RNO FROM transformed_evo.stg_mid_platform_citi_banamex_mx SMP LEFT JOIN transformed_evo.d_platform_gateway_cl DPG ON DPG.KS_PLATFORM = SMP.KS_PLATFORM WHERE SMP.KS_PLATFORM NOT IN ('030', '130', '140') ) TOTAL WHERE RNO = 1 ) ONE LEFT JOIN ( SELECT D_ID_MERCHANT, RTRIM( MAX(CASE RNO WHEN 1 THEN KS_PLATFORM ELSE '' END) || ',' || MAX(CASE RNO WHEN 2 THEN KS_PLATFORM ELSE '' END) || ',' || MAX(CASE RNO WHEN 3 THEN KS_PLATFORM ELSE '' END) || ',' || MAX(CASE RNO WHEN 4 THEN KS_PLATFORM ELSE '' END) || ',' || MAX(CASE RNO WHEN 5 THEN KS_PLATFORM ELSE '' END) || ',' || MAX(CASE RNO WHEN 6 THEN KS_PLATFORM ELSE '' END) || ',' || MAX(CASE RNO WHEN 7 THEN KS_PLATFORM ELSE '' END) || ',' || MAX(CASE RNO WHEN 8 THEN KS_PLATFORM ELSE '' END) || ',' || MAX(CASE RNO WHEN 9 THEN KS_PLATFORM ELSE '' END) || ',' || MAX(CASE RNO WHEN 10 THEN KS_PLATFORM ELSE '' END) || ',' || MAX(CASE RNO WHEN 11 THEN KS_PLATFORM ELSE '' END) || ',' || MAX(CASE RNO WHEN 12 THEN KS_PLATFORM ELSE '' END) || ',' || MAX(CASE RNO WHEN 13 THEN KS_PLATFORM ELSE '' END), ',') AS KS_PLATFORM_CONCAT, MAX(RNO) AS KS_PLATFORM_CONCAT_NUM, RTRIM( MAX(CASE RNO WHEN 1 THEN DN_SOURCE_ORDER ELSE '' END) || ',' || MAX(CASE RNO WHEN 2 THEN DN_SOURCE_ORDER ELSE '' END) || ',' || MAX(CASE RNO WHEN 3 THEN DN_SOURCE_ORDER ELSE '' END) || ',' || MAX(CASE RNO WHEN 4 THEN DN_SOURCE_ORDER ELSE '' END) || ',' || MAX(CASE RNO WHEN 5 THEN DN_SOURCE_ORDER ELSE '' END) || ',' || MAX(CASE RNO WHEN 6 THEN DN_SOURCE_ORDER ELSE '' END) || ',' || MAX(CASE RNO WHEN 7 THEN DN_SOURCE_ORDER ELSE '' END) || ',' || MAX(CASE RNO WHEN 8 THEN DN_SOURCE_ORDER ELSE '' END) || ',' || MAX(CASE RNO WHEN 9 THEN DN_SOURCE_ORDER ELSE '' END) || ',' || MAX(CASE RNO WHEN 10 THEN DN_SOURCE_ORDER ELSE '' END) || ',' || MAX(CASE RNO WHEN 11 THEN DN_SOURCE_ORDER ELSE '' END) || ',' || MAX(CASE RNO WHEN 12 THEN DN_SOURCE_ORDER ELSE '' END) || ',' || MAX(CASE RNO WHEN 13 THEN DN_SOURCE_ORDER ELSE '' END), ',') AS DN_SOURCE_ORDER_CONCAT FROM ( SELECT D_ID_MERCHANT, SAFE_CAST(CONCAT.KS_PLATFORM AS STRING) AS KS_PLATFORM, SAFE_CAST(CONCAT.DN_SOURCE_ORDER AS STRING) AS DN_SOURCE_ORDER, ROW_NUMBER() OVER ( PARTITION BY D_ID_MERCHANT ORDER BY DN_SOURCE_ORDER ASC, DPG.DN_PLATFORM_HIERARCHY_ORDER ASC ) AS RNO FROM ( SELECT D_ID_MERCHANT, KS_PLATFORM, MIN(DN_SOURCE_ORDER) AS DN_SOURCE_ORDER FROM ( SELECT SMP.D_ID_MERCHANT, SMP.KS_PLATFORM, MIN(DN_SOURCE_ORDER) AS DN_SOURCE_ORDER FROM transformed_evo.stg_mid_platform_citi_banamex_mx SMP WHERE SMP.KS_PLATFORM NOT IN ('030', '130', '140') GROUP BY SMP.D_ID_MERCHANT, SMP.KS_PLATFORM ) TOTAL GROUP BY D_ID_MERCHANT, KS_PLATFORM ) CONCAT LEFT JOIN transformed_evo.d_platform_gateway_cl DPG ON DPG.KS_PLATFORM = CONCAT.KS_PLATFORM GROUP BY D_ID_MERCHANT, SAFE_CAST(CONCAT.KS_PLATFORM AS STRING), CONCAT.KS_PLATFORM, CONCAT.DN_SOURCE_ORDER, DPG.DN_PLATFORM_HIERARCHY_ORDER ) Total GROUP BY D_ID_MERCHANT ) CONCAT ON ONE.D_ID_MERCHANT = CONCAT.D_ID_MERCHANT LEFT JOIN ( SELECT D_ID_MERCHANT, RTRIM( MAX(CASE RNO WHEN 1 THEN KS_PLATFORM ELSE '' END) || ',' || MAX(CASE RNO WHEN 2 THEN KS_PLATFORM ELSE '' END) || ',' || MAX(CASE RNO WHEN 3 THEN KS_PLATFORM ELSE '' END) || ',' || MAX(CASE RNO WHEN 4 THEN KS_PLATFORM ELSE '' END) || ',' || MAX(CASE RNO WHEN 5 THEN KS_PLATFORM ELSE '' END) || ',' || MAX(CASE RNO WHEN 6 THEN KS_PLATFORM ELSE '' END) || ',' || MAX(CASE RNO WHEN 7 THEN KS_PLATFORM ELSE '' END) || ',' || MAX(CASE RNO WHEN 8 THEN KS_PLATFORM ELSE '' END) || ',' || MAX(CASE RNO WHEN 9 THEN KS_PLATFORM ELSE '' END) || ',' || MAX(CASE RNO WHEN 10 THEN KS_PLATFORM ELSE '' END) || ',' || MAX(CASE RNO WHEN 11 THEN KS_PLATFORM ELSE '' END) || ',' || MAX(CASE RNO WHEN 12 THEN KS_PLATFORM ELSE '' END) || ',' || MAX(CASE RNO WHEN 13 THEN KS_PLATFORM ELSE '' END), ',') AS KS_PLATFORM_CONCAT_TOTAL, MAX(RNO) AS KS_PLATFORM_CONCAT_NUM_TOTAL, RTRIM( MAX(CASE RNO WHEN 1 THEN DN_SOURCE_ORDER ELSE '' END) || ',' || MAX(CASE RNO WHEN 2 THEN DN_SOURCE_ORDER ELSE '' END) || ',' || MAX(CASE RNO WHEN 3 THEN DN_SOURCE_ORDER ELSE '' END) || ',' || MAX(CASE RNO WHEN 4 THEN DN_SOURCE_ORDER ELSE '' END) || ',' || MAX(CASE RNO WHEN 5 THEN DN_SOURCE_ORDER ELSE '' END) || ',' || MAX(CASE RNO WHEN 6 THEN DN_SOURCE_ORDER ELSE '' END) || ',' || MAX(CASE RNO WHEN 7 THEN DN_SOURCE_ORDER ELSE '' END) || ',' || MAX(CASE RNO WHEN 8 THEN DN_SOURCE_ORDER ELSE '' END) || ',' || MAX(CASE RNO WHEN 9 THEN DN_SOURCE_ORDER ELSE '' END) || ',' || MAX(CASE RNO WHEN 10 THEN DN_SOURCE_ORDER ELSE '' END) || ',' || MAX(CASE RNO WHEN 11 THEN DN_SOURCE_ORDER ELSE '' END) || ',' || MAX(CASE RNO WHEN 12 THEN DN_SOURCE_ORDER ELSE '' END) || ',' || MAX(CASE RNO WHEN 13 THEN DN_SOURCE_ORDER ELSE '' END), ',') AS DN_SOURCE_ORDER_CONCAT_TOTAL FROM ( SELECT D_ID_MERCHANT, SAFE_CAST(CONCAT.KS_PLATFORM AS STRING) AS KS_PLATFORM, SAFE_CAST(CONCAT.DN_SOURCE_ORDER AS STRING) AS DN_SOURCE_ORDER, ROW_NUMBER() OVER ( PARTITION BY D_ID_MERCHANT ORDER BY DN_SOURCE_ORDER ASC, DPG.DN_PLATFORM_HIERARCHY_ORDER ASC ) AS RNO FROM ( SELECT D_ID_MERCHANT, KS_PLATFORM, MIN(DN_SOURCE_ORDER) AS DN_SOURCE_ORDER FROM ( SELECT SMP.D_ID_MERCHANT, SMP.KS_PLATFORM, MIN(DN_SOURCE_ORDER) AS DN_SOURCE_ORDER FROM transformed_evo.stg_mid_platform_citi_banamex_mx SMP WHERE SMP.KS_PLATFORM IN ('030', '130', '140') GROUP BY SMP.D_ID_MERCHANT, SMP.KS_PLATFORM ) TOTAL GROUP BY D_ID_MERCHANT, KS_PLATFORM ) CONCAT LEFT JOIN transformed_evo.d_platform_gateway_cl DPG ON DPG.KS_PLATFORM = CONCAT.KS_PLATFORM GROUP BY D_ID_MERCHANT, SAFE_CAST(CONCAT.KS_PLATFORM AS STRING), CONCAT.KS_PLATFORM, CONCAT.DN_SOURCE_ORDER, DPG.DN_PLATFORM_HIERARCHY_ORDER ) Total GROUP BY D_ID_MERCHANT ) CONCAT_TOTAL ON ONE.D_ID_MERCHANT = CONCAT_TOTAL.D_ID_MERCHANT;"


Query8="DELETE FROM transformed_evo_sensitive.tmp_vol_exchange_detail_citi_banamex_mx WHERE d_date_file >= PARSE_DATE('%Y%m%d', EXTRACT(YEAR FROM DATE_SUB(DATE_ADD(current_date(), INTERVAL 27 DAY), INTERVAL EXTRACT(DAY FROM DATE_ADD(current_date(), INTERVAL 27 DAY)) DAY)) || LPAD( CAST(EXTRACT(MONTH FROM DATE_SUB(DATE_ADD(current_date(), INTERVAL 27 DAY), INTERVAL EXTRACT(DAY FROM DATE_ADD(current_date(), INTERVAL 26 DAY)) DAY) - INTERVAL 1 MONTH) AS STRING), 2, '0' ) || '01' ); "


Query9="INSERT INTO transformed_evo_sensitive.tmp_vol_exchange_detail_citi_banamex_mx SELECT etlbatchid, etl_batch_date, tmp_vol_exchange_detail_citi_banamex_mx_sk, create_date_time, update_date_time, year, month, d_id_merchant, d_account_cardholder, d_number_authorization, d_amount_transaction, d_number_promotion_payments, importe_total, trx_total, d_amount_exchange_fee, d_code_transaction, d_bin_acquirer, d_number_acquirer_reference, d_amount_cashback, d_code_currency_destination, d_type_promotion_plan, d_date_file, ds_source, kn_acquirer_intern FROM ( SELECT etlbatchid, etl_batch_date, vw_national_exchange_multiacquirer_mx_sk AS tmp_vol_exchange_detail_citi_banamex_mx_sk, CURRENT_TIMESTAMP() AS create_date_time, CURRENT_TIMESTAMP() AS update_date_time, year, month, d_id_merchant, d_account_cardholder, d_number_authorization, d_amount_transaction, d_number_promotion_payments, importe_total, trx_total, d_amount_exchange_fee, d_code_transaction, d_bin_acquirer, d_number_acquirer_reference, d_amount_cashback, d_code_currency_destination, d_type_promotion_plan, d_date_file, ds_source, kn_acquirer_intern FROM ( SELECT MAX(etlbatchid) AS etlbatchid, MAX(etl_batch_date) AS etl_batch_date, year, month, d_id_merchant, STRING_AGG(vw_national_exchange_multiacquirer_mx_sk, ',') AS vw_national_exchange_multiacquirer_mx_sk, TRIM(d_account_cardholder) AS d_account_cardholder, TRIM(d_number_authorization) AS d_number_authorization, d_amount_transaction, d_number_promotion_payments, SUM(importe) AS importe_total, SUM(trx) AS trx_total, d_amount_exchange_fee, TRIM(d_code_transaction) AS d_code_transaction, TRIM(d_bin_acquirer) AS d_bin_acquirer, TRIM(d_number_acquirer_reference) AS d_number_acquirer_reference, d_amount_cashback, d_code_currency_destination, d_type_promotion_plan, d_date_file, TRIM(ds_source) AS ds_source, kn_acquirer_intern FROM ( SELECT MAX(nacional_mx.etlbatchid) AS etlbatchid, MAX(nacional_mx.etl_batch_date) AS etl_batch_date, STRING_AGG(vw_national_exchange_multiacquirer_mx_sk, ',') AS vw_national_exchange_multiacquirer_mx_sk, EXTRACT(year FROM DATE_SUB(d_date_file, INTERVAL 1 day)) AS year, EXTRACT(month FROM DATE_SUB(d_date_file, INTERVAL 1 day)) AS month, d_id_merchant, d_account_cardholder, d_number_authorization, SAFE_CAST( SUM( CASE WHEN TRIM(nacional_mx.d_code_transaction) = '05' THEN nacional_mx.d_amount_transaction WHEN TRIM(nacional_mx.d_code_transaction) = '06' THEN nacional_mx.d_amount_transaction * -1 ELSE 0 END) AS numeric) AS d_amount_transaction, d_number_promotion_payments, SAFE_CAST( SUM( CASE WHEN TRIM(nacional_mx.d_code_transaction) = '05' THEN nacional_mx.d_amount_exchange_fee WHEN TRIM(nacional_mx.d_code_transaction) = '06' THEN nacional_mx.d_amount_exchange_fee * -1 ELSE 0 END) AS numeric) AS d_amount_exchange_fee, TRIM(d_code_transaction) AS d_code_transaction, d_bin_acquirer, d_number_acquirer_reference, SAFE_CAST(d_amount_cashback AS numeric) AS d_amount_cashback, d_code_currency_destination AS d_code_currency_destination, d_type_promotion_plan, DATE_SUB(d_date_file, INTERVAL 1 day) AS d_date_file, SUM( CASE WHEN TRIM(nacional_mx.d_code_transaction) = '05' THEN nacional_mx.d_amount_transaction ELSE CASE WHEN TRIM(nacional_mx.d_code_transaction) = '06' THEN nacional_mx.d_amount_transaction * -1 ELSE 0 END END) AS importe, SUM( CASE WHEN TRIM(nacional_mx.d_code_transaction) = '05' THEN 1 ELSE CASE WHEN TRIM(nacional_mx.d_code_transaction) = '06' THEN 1 ELSE 0 END END) AS trx, 'V_NATIONAL_EXCHANGE' AS ds_source, kn_acquirer_intern AS kn_acquirer_intern FROM transformed_evo_sensitive.vw_national_exchange_multiacquirer_mx nacional_mx WHERE DATE_SUB(nacional_mx.d_date_file, INTERVAL 1 day) >= PARSE_DATE('%Y%m%d', EXTRACT(YEAR FROM DATE_SUB(DATE_ADD(current_date(), INTERVAL 27 DAY), INTERVAL EXTRACT(DAY FROM DATE_ADD(current_date(), INTERVAL 27 DAY)) DAY)) || LPAD( CAST(EXTRACT(MONTH FROM DATE_SUB(DATE_ADD(current_date(), INTERVAL 27 DAY), INTERVAL EXTRACT(DAY FROM DATE_ADD(current_date(), INTERVAL 26 DAY)) DAY) - INTERVAL 1 MONTH) AS STRING), 2, '0' ) || '01' ) AND d_code_code = '1' AND ( TRIM(nacional_mx.d_code_transaction) = '05' OR TRIM(nacional_mx.d_code_transaction) = '06') GROUP BY EXTRACT(year FROM DATE_SUB(d_date_file, INTERVAL 1 day)), EXTRACT(month FROM DATE_SUB(d_date_file, INTERVAL 1 day)), d_id_merchant, d_account_cardholder, d_number_authorization, SAFE_CAST((CASE WHEN TRIM(nacional_mx.d_code_transaction) = '05' THEN nacional_mx.d_amount_transaction WHEN TRIM(nacional_mx.d_code_transaction) = '06' THEN nacional_mx.d_amount_transaction * -1 ELSE 0 END) AS numeric), d_number_promotion_payments, d_code_transaction, d_bin_acquirer, d_number_acquirer_reference, SAFE_CAST(d_amount_cashback AS numeric), d_code_currency_destination, d_type_promotion_plan, DATE_SUB(d_date_file, INTERVAL 1 day), kn_acquirer_intern UNION DISTINCT SELECT MAX(internacional_mx.etlbatchid) AS etlbatchid, MAX(internacional_mx.etl_batch_date) AS etl_batch_date, STRING_AGG(vw_intercambio_internacional_mx_sk, ',') AS vw_intercambio_internacional_mx_sk, EXTRACT( year FROM DATE_SUB(internacional_mx.d_date_file, INTERVAL 1 day)) AS year, EXTRACT( month FROM DATE_SUB(internacional_mx.d_date_file, INTERVAL 1 day)) AS month, CASE WHEN bdn.d_id_discover IS NOT NULL THEN bdn.d_id_merchant ELSE CASE WHEN LENGTH( SAFE_CAST(internacional_mx.d_id_merchant AS string)) BETWEEN 4 AND 7 THEN internacional_mx.d_id_merchant ELSE 0 END END AS d_id_merchant, d_account_cardholder, d_authorization_number AS d_number_authorization, SAFE_CAST( SUM( CASE WHEN TRIM(internacional_mx.d_code_transaction) = '05' THEN internacional_mx.d_amount_transaction WHEN TRIM(internacional_mx.d_code_transaction) = '06' THEN internacional_mx.d_amount_transaction * -1 ELSE 0 END) AS numeric) AS d_amount_transaction, 0 AS d_number_promotion_payments, 0 AS d_amount_exchange_fee, TRIM(d_code_transaction) AS d_code_transaction, d_bin_acquirer, d_acquirer_reference_number, 0.00 AS d_amount_cashback, d_code_currency_int, NULL AS d_type_promotion_plan, DATE_SUB(internacional_mx.d_date_file, INTERVAL 1 day), SUM( CASE WHEN TRIM(internacional_mx.d_code_transaction) = '05' THEN CASE WHEN d_code_currency = '840' THEN (d_amount_transaction) * mn_usd_exchange_rate ELSE d_amount_transaction END ELSE CASE WHEN TRIM(internacional_mx.d_code_transaction) = '06' THEN CASE WHEN d_code_currency = '840' THEN (d_amount_transaction) * -1 * mn_usd_exchange_rate ELSE d_amount_transaction * -1 END ELSE 0 END END) AS importe, SUM( CASE WHEN TRIM(internacional_mx.d_code_transaction) IN ('05', '06') THEN 1 ELSE 0 END) AS trx, 'V_INTERNATIONAL_EXCHANGE' AS ds_source, 1 AS kn_acquirer_intern FROM transformed_evo_sensitive.vw_intercambio_internacional_mx internacional_mx LEFT JOIN transformed_evo.d_usd_exchange_rate_mx usd ON usd.dd_date = DATE_SUB( internacional_mx.d_date_file, INTERVAL 1 day) LEFT JOIN transformed_evo_sensitive.vw_bdn_diario_mx bdn ON TRIM(SAFE_CAST(internacional_mx.d_id_merchant AS string)) = TRIM(bdn.d_id_discover) WHERE ( DATE_SUB(internacional_mx.d_date_file, INTERVAL 1 day) >= PARSE_DATE('%Y%m%d', EXTRACT(YEAR FROM DATE_SUB(DATE_ADD(current_date(), INTERVAL 27 DAY), INTERVAL EXTRACT(DAY FROM DATE_ADD(current_date(), INTERVAL 27 DAY)) DAY)) || LPAD( CAST(EXTRACT(MONTH FROM DATE_SUB(DATE_ADD(current_date(), INTERVAL 27 DAY), INTERVAL EXTRACT(DAY FROM DATE_ADD(current_date(), INTERVAL 26 DAY)) DAY) - INTERVAL 1 MONTH) AS STRING), 2, '0' ) || '01' )) AND ( TRIM(internacional_mx.d_code_transaction) = '05' OR TRIM(internacional_mx.d_code_transaction) = '06') GROUP BY EXTRACT( year FROM DATE_SUB(internacional_mx.d_date_file, INTERVAL 1 day)), EXTRACT( month FROM DATE_SUB(internacional_mx.d_date_file, INTERVAL 1 day)), d_id_merchant, CASE WHEN bdn.d_id_discover IS NOT NULL THEN bdn.d_id_merchant ELSE CASE WHEN LENGTH( SAFE_CAST(internacional_mx.d_id_merchant AS string)) BETWEEN 4 AND 7 THEN internacional_mx.d_id_merchant ELSE 0 END END, d_account_cardholder, d_authorization_number, SAFE_CAST( ( CASE WHEN TRIM(internacional_mx.d_code_transaction) = '05' THEN internacional_mx.d_amount_transaction WHEN TRIM(internacional_mx.d_code_transaction) = '06' THEN internacional_mx.d_amount_transaction * -1 ELSE 0 END) AS numeric), d_code_transaction, d_bin_acquirer, d_acquirer_reference_number, d_code_currency_int, DATE_SUB(internacional_mx.d_date_file, INTERVAL 1 day) ) total GROUP BY year, month, d_id_merchant, d_account_cardholder, d_number_authorization, d_amount_transaction, d_number_promotion_payments, d_amount_exchange_fee, d_code_transaction, d_bin_acquirer, d_number_acquirer_reference, d_amount_cashback, d_code_currency_destination, d_type_promotion_plan, d_date_file, ds_source, kn_acquirer_intern ) tmp ) QUALIFY ROW_NUMBER() OVER ( PARTITION BY d_id_merchant, d_account_cardholder, d_number_authorization, d_amount_transaction ORDER BY d_date_file, ds_source, d_number_promotion_payments, importe_total, trx_total, d_amount_exchange_fee, d_code_transaction, d_bin_acquirer, d_number_acquirer_reference, d_amount_cashback, d_code_currency_destination, d_type_promotion_plan ) = 1;"


Query10="DELETE FROM consumption_evo_bi.stg_vol_exchange_detail_citi_banamex_mx WHERE  D_DATE_FILE>= PARSE_DATE('%Y%m%d', EXTRACT(YEAR FROM DATE_SUB(DATE_ADD(current_date(), INTERVAL 27 DAY), INTERVAL EXTRACT(DAY FROM DATE_ADD(current_date(), INTERVAL 27 DAY)) DAY)) || LPAD( CAST(EXTRACT(MONTH FROM DATE_SUB(DATE_ADD(current_date(), INTERVAL 27 DAY), INTERVAL EXTRACT(DAY FROM DATE_ADD(current_date(), INTERVAL 26 DAY)) DAY) - INTERVAL 1 MONTH) AS STRING), 2, '0' ) || '01' );"


Query11="INSERT INTO consumption_evo_bi.stg_vol_exchange_detail_citi_banamex_mx ( etlbatchid, etl_batch_date, stg_vol_exchange_detail_citi_banamex_mx_sk, create_date_time, update_date_time, year, month, d_id_merchant, d_account_cardholder, d_number_authorization, d_amount_transaction, d_number_promotion_payments, importe_total, trx_total, d_amount_exchange_fee, d_code_transaction, d_bin_acquirer, d_number_acquirer_reference, d_amount_cashback, d_code_currency_destination, d_type_promotion_plan, d_date_file, ds_source, ds_linked_source, d_process_date, kn_acquirer_intern, d_issuer_bin) SELECT CAST(${etlbatchid} AS STRING) AS etlbatchid, CURRENT_DATE() AS etl_batch_date, GENERATE_UUID() AS stg_vol_exchange_detail_citi_banamex_mx_sk, CURRENT_TIMESTAMP() AS create_date_time, CURRENT_TIMESTAMP() AS update_date_time, YEAR, MONTH, D_ID_MERCHANT, TRIM(D_ACCOUNT_CARDHOLDER), TRIM(D_NUMBER_AUTHORIZATION), D_AMOUNT_TRANSACTION, SAFE_CAST(D_NUMBER_PROMOTION_PAYMENTS AS STRING) AS D_NUMBER_PROMOTION_PAYMENTS, SUM(IMPORTE) AS IMPORTE_TOTAL, SUM(TRX_TOTAL) AS TRX_TOTAL, SAFE_CAST(D_AMOUNT_EXCHANGE_FEE AS STRING) AS D_AMOUNT_EXCHANGE_FEE, TRIM(D_CODE_TRANSACTION), TRIM(D_BIN_ACQUIRER), TRIM(D_NUMBER_ACQUIRER_REFERENCE), D_AMOUNT_CASHBACK, TRIM(D_CODE_CURRENCY_DESTINATION), CAST(D_TYPE_PROMOTION_PLAN AS STRING) AS D_TYPE_PROMOTION_PLAN, D_DATE_FILE, TRIM(DS_SOURCE), TRIM(DS_LINKED_SOURCE), D_FECHA_PROCESO, KN_ACQUIRER_INTERN, TRIM(D_ISSUER_BIN) FROM ( SELECT EXTRACT(YEAR FROM D_TRANSACTION_DATE) AS YEAR, EXTRACT(MONTH FROM D_TRANSACTION_DATE) AS MONTH, X.D_ID_MERCHANT AS D_ID_MERCHANT, D_NUMBER_CARD AS D_ACCOUNT_CARDHOLDER, D_AUTHORIZATION_NUMBER AS D_NUMBER_AUTHORIZATION, SAFE_CAST( IFNULL( ( CASE WHEN D_TRANSACTION_TYPE = 'DEVOLUCION' THEN D_TRANSACTION_AMOUNT * -1 ELSE D_TRANSACTION_AMOUNT END), 0.0) AS NUMERIC) AS D_AMOUNT_TRANSACTION, SAFE_CAST(D_DEFERMENT AS STRING) AS D_NUMBER_PROMOTION_PAYMENTS, SUM( CASE WHEN D_CURRENCY_TYPE = '840' THEN ( SAFE_CAST( IFNULL( ( CASE WHEN D_TRANSACTION_TYPE = 'DEVOLUCION' THEN D_TRANSACTION_AMOUNT * -1 ELSE D_TRANSACTION_AMOUNT END), 0.0) AS NUMERIC)) * MN_USD_EXCHANGE_RATE ELSE SAFE_CAST( IFNULL( ( CASE WHEN D_TRANSACTION_TYPE = 'DEVOLUCION' THEN D_TRANSACTION_AMOUNT * -1 ELSE D_TRANSACTION_AMOUNT END), 0.0) AS NUMERIC) END) AS IMPORTE, COUNT( SAFE_CAST( IFNULL( ( CASE WHEN D_TRANSACTION_TYPE = 'DEVOLUCION' THEN D_TRANSACTION_AMOUNT * -1 ELSE D_TRANSACTION_AMOUNT END), 0.0) AS NUMERIC)) AS TRX_TOTAL, IFNULL( TVED.D_AMOUNT_EXCHANGE_FEE, CASE D_BREAKDOWN WHEN 1 THEN SAFE_CAST( IFNULL( ( CASE WHEN D_TRANSACTION_TYPE = 'DEVOLUCION' THEN D_TRANSACTION_AMOUNT * -1 ELSE D_TRANSACTION_AMOUNT END), 0.0) AS NUMERIC) * DECRED.MF_CREDIT_RATE_FEE WHEN 2 THEN CASE WHEN CASE WHEN DS_NATURE = 'CRDITO' THEN SAFE_CAST( IFNULL( ( CASE WHEN D_TRANSACTION_TYPE = 'DEVOLUCION' THEN D_TRANSACTION_AMOUNT * -1 ELSE D_TRANSACTION_AMOUNT END), 0.0) AS NUMERIC) * DECRED.MF_CREDIT_RATE_FEE ELSE SAFE_CAST( IFNULL( ( CASE WHEN D_TRANSACTION_TYPE = 'DEVOLUCION' THEN D_TRANSACTION_AMOUNT * -1 ELSE D_TRANSACTION_AMOUNT END), 0.0) AS NUMERIC) * DEDEB.MF_DEBIT_RATE_FEE END > 13.5 THEN 13.5 ELSE CASE WHEN DS_NATURE = 'CRDITO' THEN SAFE_CAST( IFNULL( ( CASE WHEN D_TRANSACTION_TYPE = 'DEVOLUCION' THEN D_TRANSACTION_AMOUNT * -1 ELSE D_TRANSACTION_AMOUNT END), 0.0) AS NUMERIC) * DECRED.MF_CREDIT_RATE_FEE ELSE SAFE_CAST( IFNULL( ( CASE WHEN D_TRANSACTION_TYPE = 'DEVOLUCION' THEN D_TRANSACTION_AMOUNT * -1 ELSE D_TRANSACTION_AMOUNT END), 0.0) AS NUMERIC) * DEDEB.MF_DEBIT_RATE_FEE END END WHEN 4 THEN CASE WHEN DS_NATURE = 'CRDITO' THEN SAFE_CAST( IFNULL( ( CASE WHEN D_TRANSACTION_TYPE = 'DEVOLUCION' THEN D_TRANSACTION_AMOUNT * -1 ELSE D_TRANSACTION_AMOUNT END), 0.0) AS NUMERIC) * DECRED.MF_CREDIT_RATE_FEE ELSE CASE WHEN ( BDN.D_CATEGORY_EXCHANGE_DEBIT >= 1 AND BDN.D_CATEGORY_EXCHANGE_DEBIT <= 7) OR BDN.D_CATEGORY_EXCHANGE_DEBIT = 50 THEN DEDEB.MF_DEBIT_RATE_FEE ELSE SAFE_CAST( IFNULL( ( CASE WHEN D_TRANSACTION_TYPE = 'DEVOLUCION' THEN D_TRANSACTION_AMOUNT * -1 ELSE D_TRANSACTION_AMOUNT END), 0.0) AS NUMERIC) * DEDEB.MF_DEBIT_RATE_FEE END END WHEN 3 THEN CASE WHEN DS_NATURE = 'CRDITO' THEN SAFE_CAST( IFNULL( ( CASE WHEN D_TRANSACTION_TYPE = 'DEVOLUCION' THEN D_TRANSACTION_AMOUNT * -1 ELSE D_TRANSACTION_AMOUNT END), 0.0) AS NUMERIC) * DECRED.MF_CREDIT_RATE_FEE ELSE CASE WHEN ( BDN.D_CATEGORY_EXCHANGE_DEBIT >= 1 AND BDN.D_CATEGORY_EXCHANGE_DEBIT <= 7) OR BDN.D_CATEGORY_EXCHANGE_DEBIT = 50 THEN DEDEB.MF_DEBIT_RATE_FEE ELSE SAFE_CAST( IFNULL( ( CASE WHEN D_TRANSACTION_TYPE = 'DEVOLUCION' THEN D_TRANSACTION_AMOUNT * -1 ELSE D_TRANSACTION_AMOUNT END), 0.0) AS NUMERIC) * DEDEB.MF_DEBIT_RATE_FEE END END ELSE SAFE_CAST( IFNULL( ( CASE WHEN D_TRANSACTION_TYPE = 'DEVOLUCION' THEN D_TRANSACTION_AMOUNT * -1 ELSE D_TRANSACTION_AMOUNT END), 0.0) AS NUMERIC) * DEDEB.MF_DEBIT_RATE_FEE END) AS D_AMOUNT_EXCHANGE_FEE, CASE WHEN SAFE_CAST( IFNULL( ( CASE WHEN D_TRANSACTION_TYPE = 'DEVOLUCION' THEN D_TRANSACTION_AMOUNT * -1 ELSE D_TRANSACTION_AMOUNT END), 0.0) AS NUMERIC) >= 0 THEN '05' ELSE '06' END AS D_CODE_TRANSACTION, TVED.D_BIN_ACQUIRER, D_REFERENCE_NUMBER_PAY AS D_NUMBER_ACQUIRER_REFERENCE, SAFE_CAST(D_CASHBACK_AMOUNT AS NUMERIC) AS D_AMOUNT_CASHBACK, SAFE_CAST(D_CURRENCY_TYPE AS string) AS D_CODE_CURRENCY_DESTINATION, TVED.D_TYPE_PROMOTION_PLAN, D_TRANSACTION_DATE AS D_DATE_FILE, 'V_LIQUIDACION_ACEPTADAS_RECHAZADAS' AS DS_SOURCE, TVED.DS_SOURCE AS DS_LINKED_SOURCE, D_PROCESS_DATE AS D_FECHA_PROCESO, 2 AS KN_ACQUIRER_INTERN, D_ISSUER_BIN FROM transformed_evo_sensitive.vw_accepted_rejected_cb_mx X LEFT JOIN transformed_evo.d_bin_national_la DB ON DB.KS_BIN = X.D_ISSUER_BIN LEFT JOIN transformed_evo.d_usd_exchange_rate_la USD ON USD.DD_DATE = X.D_TRANSACTION_DATE LEFT JOIN transformed_evo_sensitive.tmp_vol_exchange_detail_citi_banamex_mx TVED ON TVED.D_ID_MERCHANT = X.D_ID_MERCHANT AND SUBSTRING(TVED.D_ACCOUNT_CARDHOLDER, 1, 6) = SUBSTRING(X.D_NUMBER_CARD, 1, 6) AND SUBSTRING( TVED.D_ACCOUNT_CARDHOLDER, LENGTH(TVED.D_ACCOUNT_CARDHOLDER) - 1, 4) = SUBSTRING(X.D_NUMBER_CARD, LENGTH(X.D_NUMBER_CARD) - 1, 4) AND TVED.D_NUMBER_AUTHORIZATION = X.D_AUTHORIZATION_NUMBER AND TVED.D_AMOUNT_TRANSACTION = SAFE_CAST( IFNULL( ( CASE WHEN X.D_TRANSACTION_TYPE = 'DEVOLUCION' THEN X.D_TRANSACTION_AMOUNT * -1 ELSE X.D_TRANSACTION_AMOUNT END), 0.0) AS NUMERIC) LEFT JOIN transformed_evo_sensitive.vw_bdn_diario_mx BDN ON BDN.D_ID_MERCHANT = X.D_ID_MERCHANT LEFT JOIN transformed_evo.d_exchange_category_rate_fee_la DEDEB ON DEDEB.KN_EXCHANGE_CATEGORY = BDN.D_CATEGORY_EXCHANGE_DEBIT LEFT JOIN transformed_evo.d_exchange_category_rate_fee_la DECRED ON DECRED.KN_EXCHANGE_CATEGORY = BDN.D_CATEGORY_EXCHANGE_CREDIT WHERE (D_TRANSACTION_DATE = '2025-08-01') AND D_RISK_CODE NOT IN ('051', '052') AND D_ACEPTED_REJECTED_TYPE = 'A' GROUP BY EXTRACT(YEAR FROM D_TRANSACTION_DATE), EXTRACT(MONTH FROM D_TRANSACTION_DATE), X.D_ID_MERCHANT, D_NUMBER_CARD, D_AUTHORIZATION_NUMBER, SAFE_CAST( IFNULL( ( CASE WHEN D_TRANSACTION_TYPE = 'DEVOLUCION' THEN D_TRANSACTION_AMOUNT * -1 ELSE D_TRANSACTION_AMOUNT END), 0.0) AS NUMERIC), SAFE_CAST(D_DEFERMENT AS STRING), SAFE_CAST(D_CASHBACK_AMOUNT AS NUMERIC), D_TRANSACTION_DATE, IFNULL( TVED.D_AMOUNT_EXCHANGE_FEE, CASE D_BREAKDOWN WHEN 1 THEN SAFE_CAST( IFNULL( ( CASE WHEN D_TRANSACTION_TYPE = 'DEVOLUCION' THEN D_TRANSACTION_AMOUNT * -1 ELSE D_TRANSACTION_AMOUNT END), 0.0) AS NUMERIC) * DECRED.MF_CREDIT_RATE_FEE WHEN 2 THEN CASE WHEN CASE WHEN DS_NATURE = 'CRDITO' THEN SAFE_CAST( IFNULL( ( CASE WHEN D_TRANSACTION_TYPE = 'DEVOLUCION' THEN D_TRANSACTION_AMOUNT * -1 ELSE D_TRANSACTION_AMOUNT END), 0.0) AS NUMERIC) * DECRED.MF_CREDIT_RATE_FEE ELSE SAFE_CAST( IFNULL( ( CASE WHEN D_TRANSACTION_TYPE = 'DEVOLUCION' THEN D_TRANSACTION_AMOUNT * -1 ELSE D_TRANSACTION_AMOUNT END), 0.0) AS NUMERIC) * DEDEB.MF_DEBIT_RATE_FEE END > 13.5 THEN 13.5 ELSE CASE WHEN DS_NATURE = 'CRDITO' THEN SAFE_CAST( IFNULL( ( CASE WHEN D_TRANSACTION_TYPE = 'DEVOLUCION' THEN D_TRANSACTION_AMOUNT * -1 ELSE D_TRANSACTION_AMOUNT END), 0.0) AS NUMERIC) * DECRED.MF_CREDIT_RATE_FEE ELSE SAFE_CAST( IFNULL( ( CASE WHEN D_TRANSACTION_TYPE = 'DEVOLUCION' THEN D_TRANSACTION_AMOUNT * -1 ELSE D_TRANSACTION_AMOUNT END), 0.0) AS NUMERIC) * DEDEB.MF_DEBIT_RATE_FEE END END WHEN 4 THEN CASE WHEN DS_NATURE = 'CRDITO' THEN SAFE_CAST( IFNULL( ( CASE WHEN D_TRANSACTION_TYPE = 'DEVOLUCION' THEN D_TRANSACTION_AMOUNT * -1 ELSE D_TRANSACTION_AMOUNT END), 0.0) AS NUMERIC) * DECRED.MF_CREDIT_RATE_FEE ELSE CASE WHEN ( BDN.D_CATEGORY_EXCHANGE_DEBIT >= 1 AND BDN.D_CATEGORY_EXCHANGE_DEBIT <= 7) OR BDN.D_CATEGORY_EXCHANGE_DEBIT = 50 THEN DEDEB.MF_DEBIT_RATE_FEE ELSE SAFE_CAST( IFNULL( ( CASE WHEN D_TRANSACTION_TYPE = 'DEVOLUCION' THEN D_TRANSACTION_AMOUNT * -1 ELSE D_TRANSACTION_AMOUNT END), 0.0) AS NUMERIC) * DEDEB.MF_DEBIT_RATE_FEE END END WHEN 3 THEN CASE WHEN DS_NATURE = 'CRDITO' THEN SAFE_CAST( IFNULL( ( CASE WHEN D_TRANSACTION_TYPE = 'DEVOLUCION' THEN D_TRANSACTION_AMOUNT * -1 ELSE D_TRANSACTION_AMOUNT END), 0.0) AS NUMERIC) * DECRED.MF_CREDIT_RATE_FEE ELSE CASE WHEN ( BDN.D_CATEGORY_EXCHANGE_DEBIT >= 1 AND BDN.D_CATEGORY_EXCHANGE_DEBIT <= 7) OR BDN.D_CATEGORY_EXCHANGE_DEBIT = 50 THEN DEDEB.MF_DEBIT_RATE_FEE ELSE SAFE_CAST( IFNULL( ( CASE WHEN D_TRANSACTION_TYPE = 'DEVOLUCION' THEN D_TRANSACTION_AMOUNT * -1 ELSE D_TRANSACTION_AMOUNT END), 0.0) AS NUMERIC) * DEDEB.MF_DEBIT_RATE_FEE END END ELSE SAFE_CAST( IFNULL( ( CASE WHEN D_TRANSACTION_TYPE = 'DEVOLUCION' THEN D_TRANSACTION_AMOUNT * -1 ELSE D_TRANSACTION_AMOUNT END), 0.0) AS NUMERIC) * DEDEB.MF_DEBIT_RATE_FEE END), CASE WHEN SAFE_CAST( IFNULL( ( CASE WHEN D_TRANSACTION_TYPE = 'DEVOLUCION' THEN D_TRANSACTION_AMOUNT * -1 ELSE D_TRANSACTION_AMOUNT END), 0.0) AS NUMERIC) >= 0 THEN '05' ELSE '06' END, TVED.D_BIN_ACQUIRER, D_REFERENCE_NUMBER_PAY, TVED.D_NUMBER_ACQUIRER_REFERENCE, TVED.D_CODE_CURRENCY_DESTINATION, TVED.D_TYPE_PROMOTION_PLAN, TVED.DS_SOURCE, D_CURRENCY_TYPE, D_PROCESS_DATE, D_ISSUER_BIN UNION DISTINCT SELECT EXTRACT( YEAR FROM CASE WHEN D_FECHA_TRANSACCION = '2023-01-01' THEN '2023-01-02' ELSE D_FECHA_TRANSACCION END) AS YEAR, EXTRACT( MONTH FROM CASE WHEN D_FECHA_TRANSACCION = '2023-01-01' THEN '2023-01-02' ELSE D_FECHA_TRANSACCION END) AS MONTH, D_ID_AFILIACION AS D_ID_MERCHANT, RPAD(D_BIN_EMISOR, 12, '*') || D_CUENTA_TARJETAHABIENTE AS D_ACCOUNT_CARDHOLDER, D_NUMERO_AUTORIZACION AS D_NUMBER_AUTHORIZATION, D_IMPORTE_TRANSACCION AS D_AMOUNT_TRANSACTION, SAFE_CAST(D_DIFERIMIENTO AS STRING) AS D_NUMBER_PROMOTION_PAYMENTS, SUM( CASE WHEN D_CODIGO_MONEDA = 840 THEN (D_IMPORTE_TRANSACCION) * MN_USD_EXCHANGE_RATE ELSE D_IMPORTE_TRANSACCION END) AS IMPORTE, COUNT(D_IMPORTE_TRANSACCION) AS Trx, IFNULL( TVED.D_AMOUNT_EXCHANGE_FEE, CASE D_BREAKDOWN WHEN 1 THEN D_IMPORTE_TRANSACCION * DECRED.MF_CREDIT_RATE_FEE WHEN 2 THEN CASE WHEN CASE WHEN DS_NATURE = 'CRÉDITO' THEN D_IMPORTE_TRANSACCION * DECRED.MF_CREDIT_RATE_FEE ELSE D_IMPORTE_TRANSACCION * DEDEB.MF_DEBIT_RATE_FEE END > 13.5 THEN 13.5 ELSE CASE WHEN DS_NATURE = 'CRÉDITO' THEN D_IMPORTE_TRANSACCION * DECRED.MF_CREDIT_RATE_FEE ELSE D_IMPORTE_TRANSACCION * DEDEB.MF_DEBIT_RATE_FEE END END WHEN 4 THEN CASE WHEN DS_NATURE = 'CRÉDITO' THEN D_IMPORTE_TRANSACCION * DECRED.MF_CREDIT_RATE_FEE ELSE CASE WHEN ( BDN.D_CATEGORY_EXCHANGE_DEBIT >= 1 AND BDN.D_CATEGORY_EXCHANGE_DEBIT <= 7) OR BDN.D_CATEGORY_EXCHANGE_DEBIT = 50 THEN DEDEB.MF_DEBIT_RATE_FEE ELSE D_IMPORTE_TRANSACCION * DEDEB.MF_DEBIT_RATE_FEE END END WHEN 3 THEN CASE WHEN DS_NATURE = 'CRÉDITO' THEN D_IMPORTE_TRANSACCION * DECRED.MF_CREDIT_RATE_FEE ELSE CASE WHEN ( BDN.D_CATEGORY_EXCHANGE_DEBIT >= 1 AND BDN.D_CATEGORY_EXCHANGE_DEBIT <= 7) OR BDN.D_CATEGORY_EXCHANGE_DEBIT = 50 THEN DEDEB.MF_DEBIT_RATE_FEE ELSE D_IMPORTE_TRANSACCION * DEDEB.MF_DEBIT_RATE_FEE END END ELSE D_IMPORTE_TRANSACCION * DEDEB.MF_DEBIT_RATE_FEE END) AS D_AMOUNT_EXCHANGE_FEE, CASE WHEN D_IMPORTE_TRANSACCION >= 0 THEN '05' ELSE '06' END AS D_CODE_TRANSACTION, TVED.D_BIN_ACQUIRER AS D_BIN_ACQUIRER, D_NUMERO_REFERENCIA_PAGARE AS D_NUMBER_ACQUIRER_REFERENCE, SAFE_CAST(D_IMPORTE_CASHBACK AS NUMERIC) AS D_AMOUNT_CASHBACK, SAFE_CAST(D_CODIGO_MONEDA AS STRING) AS D_CODE_CURRENCY_DESTINATION, TVED.D_TYPE_PROMOTION_PLAN AS D_TYPE_PROMOTION_PLAN, CASE WHEN D_FECHA_TRANSACCION = '2023-01-01' THEN '2023-01-02' ELSE D_FECHA_TRANSACCION END AS D_DATE_FILE, 'V_LIQUIDACION_ACEPTADAS_RECHAZADAS' AS DS_SOURCE, TVED.DS_SOURCE AS DS_LINKED_SOURCE, D_FECHA_PROCESO, 1 AS KN_ACQUIRER_INTERN, D_BIN_EMISOR AS D_ISSUER_BIN FROM transformed_evo_sensitive.vw_liquidacion_aceptadas_rechazadas_mx X LEFT JOIN transformed_evo.d_bin_national_la DB ON DB.KS_BIN = X.D_BIN_EMISOR LEFT JOIN transformed_evo.d_usd_exchange_rate_la USD ON USD.DD_DATE = X.D_FECHA_TRANSACCION LEFT JOIN transformed_evo_sensitive.tmp_vol_exchange_detail_mx TVED ON TVED.D_ID_MERCHANT = X.D_ID_AFILIACION AND TVED.D_ACCOUNT_CARDHOLDER = RPAD(X.D_BIN_EMISOR, 12, '*') || X.D_CUENTA_TARJETAHABIENTE AND TVED.D_NUMBER_AUTHORIZATION = X.D_NUMERO_AUTORIZACION AND TVED.D_AMOUNT_TRANSACTION = X.D_IMPORTE_TRANSACCION LEFT JOIN transformed_evo_sensitive.vw_bdn_diario_mx BDN ON BDN.D_ID_MERCHANT = X.D_ID_AFILIACION LEFT JOIN transformed_evo.d_exchange_category_rate_fee_la DEDEB ON DEDEB.KN_EXCHANGE_CATEGORY = BDN.D_CATEGORY_EXCHANGE_DEBIT LEFT JOIN transformed_evo.d_exchange_category_rate_fee_la DECRED ON DECRED.KN_EXCHANGE_CATEGORY = BDN.D_CATEGORY_EXCHANGE_CREDIT WHERE D_FECHA_TRANSACCION >= PARSE_DATE( '%Y%m%d', EXTRACT( YEAR FROM DATE_SUB( DATE_ADD(current_date(), INTERVAL 27 DAY), INTERVAL EXTRACT(DAY FROM DATE_ADD(current_date(), INTERVAL 27 DAY)) DAY)) || LPAD( CAST( EXTRACT( MONTH FROM DATE_SUB( DATE_ADD(current_date(), INTERVAL 27 DAY), INTERVAL EXTRACT( DAY FROM DATE_ADD(current_date(), INTERVAL 26 DAY)) DAY) - INTERVAL 1 MONTH) AS STRING), 2, '0') || '01') AND D_CODIGO_RIESGO NOT IN ('051', '052') AND D_TIPO_ACEPTADA_RECHAZADA = 'A' GROUP BY EXTRACT( YEAR FROM CASE WHEN D_FECHA_TRANSACCION = '2023-01-01' THEN '2023-01-02' ELSE D_FECHA_TRANSACCION END), EXTRACT( MONTH FROM CASE WHEN D_FECHA_TRANSACCION = '2023-01-01' THEN '2023-01-02' ELSE D_FECHA_TRANSACCION END), D_ID_AFILIACION, RPAD(D_BIN_EMISOR, 12, '*') || D_CUENTA_TARJETAHABIENTE, D_NUMERO_AUTORIZACION, D_IMPORTE_TRANSACCION, SAFE_CAST(D_DIFERIMIENTO AS STRING), SAFE_CAST(D_IMPORTE_CASHBACK AS NUMERIC), CASE WHEN D_FECHA_TRANSACCION = '2023-01-01' THEN '2023-01-02' ELSE D_FECHA_TRANSACCION END, IFNULL( TVED.D_AMOUNT_EXCHANGE_FEE, CASE D_BREAKDOWN WHEN 1 THEN D_IMPORTE_TRANSACCION * DECRED.MF_CREDIT_RATE_FEE WHEN 2 THEN CASE WHEN CASE WHEN DS_NATURE = 'CRÉDITO' THEN D_IMPORTE_TRANSACCION * DECRED.MF_CREDIT_RATE_FEE ELSE D_IMPORTE_TRANSACCION * DEDEB.MF_DEBIT_RATE_FEE END > 13.5 THEN 13.5 ELSE CASE WHEN DS_NATURE = 'CRÉDITO' THEN D_IMPORTE_TRANSACCION * DECRED.MF_CREDIT_RATE_FEE ELSE D_IMPORTE_TRANSACCION * DEDEB.MF_DEBIT_RATE_FEE END END WHEN 4 THEN CASE WHEN DS_NATURE = 'CRÉDITO' THEN D_IMPORTE_TRANSACCION * DECRED.MF_CREDIT_RATE_FEE ELSE CASE WHEN ( BDN.D_CATEGORY_EXCHANGE_DEBIT >= 1 AND BDN.D_CATEGORY_EXCHANGE_DEBIT <= 7) OR BDN.D_CATEGORY_EXCHANGE_DEBIT = 50 THEN DEDEB.MF_DEBIT_RATE_FEE ELSE D_IMPORTE_TRANSACCION * DEDEB.MF_DEBIT_RATE_FEE END END WHEN 3 THEN CASE WHEN DS_NATURE = 'CRÉDITO' THEN D_IMPORTE_TRANSACCION * DECRED.MF_CREDIT_RATE_FEE ELSE CASE WHEN ( BDN.D_CATEGORY_EXCHANGE_DEBIT >= 1 AND BDN.D_CATEGORY_EXCHANGE_DEBIT <= 7) OR BDN.D_CATEGORY_EXCHANGE_DEBIT = 50 THEN DEDEB.MF_DEBIT_RATE_FEE ELSE D_IMPORTE_TRANSACCION * DEDEB.MF_DEBIT_RATE_FEE END END ELSE D_IMPORTE_TRANSACCION * DEDEB.MF_DEBIT_RATE_FEE END), CASE WHEN D_IMPORTE_TRANSACCION >= 0 THEN '05' ELSE '06' END, TVED.D_BIN_ACQUIRER, D_NUMERO_REFERENCIA_PAGARE, TVED.D_CODE_CURRENCY_DESTINATION, TVED.D_TYPE_PROMOTION_PLAN, TVED.DS_SOURCE, D_CODIGO_MONEDA, D_FECHA_PROCESO, D_BIN_EMISOR UNION DISTINCT SELECT EXTRACT(YEAR FROM D_FECHA_TRANSACCION) AS YEAR, EXTRACT(MONTH FROM D_FECHA_TRANSACCION) AS MONTH, D_ID_AFILIACION, D_NUMERO_TARJETAHABIENTE, D_NUMERO_AUTORIZACION, D_IMPORTE_TRANSACCION, SAFE_CAST(D_DIFERIMIENTO AS STRING) AS D_NUMBER_PROMOTION_PAYMENTS, SUM(x.D_IMPORTE_TRANSACCION) AS IMPORTE, COUNT(x.D_IMPORTE_TRANSACCION) AS Trx, 0.00 AS D_AMOUNT_EXCHANGE_FEE, D_CODIGO_TRANSACCION, '0' AS D_BIN_ACQUIRER, '0' AS D_NUMBER_ACQUIRER_REFERENCE, 0.00 AS D_AMOUNT_CASHBACK, '484' AS D_CODE_CURRENCY_DESTINATION, 0 AS D_TYPE_PROMOTION_PLAN, D_FECHA_TRANSACCION AS D_DATE_FILE, 'V_AMEX_SETTLEMENT' AS DS_SOURCE, NULL AS DS_LINKED_SOURCE, D_FECHA_PROCESO, 1 KN_ACQUIRER_INTERN, SUBSTRING(D_NUMERO_TARJETAHABIENTE, 1, 6) AS D_ISSUER_BIN FROM transformed_evo_sensitive.vw_liquidacion_amex_mx X WHERE D_FECHA_TRANSACCION >= PARSE_DATE( '%Y%m%d', EXTRACT( YEAR FROM DATE_SUB( DATE_ADD(current_date(), INTERVAL 27 DAY), INTERVAL EXTRACT(DAY FROM DATE_ADD(current_date(), INTERVAL 27 DAY)) DAY)) || LPAD( CAST( EXTRACT( MONTH FROM DATE_SUB( DATE_ADD(current_date(), INTERVAL 27 DAY), INTERVAL EXTRACT( DAY FROM DATE_ADD(current_date(), INTERVAL 26 DAY)) DAY) - INTERVAL 1 MONTH) AS STRING), 2, '0') || '01') AND D_TIPO_ACEPTADA_RECHAZADA = 'A' GROUP BY EXTRACT(YEAR FROM D_FECHA_TRANSACCION), EXTRACT(MONTH FROM D_FECHA_TRANSACCION), D_ID_AFILIACION, D_NUMERO_TARJETAHABIENTE, D_NUMERO_AUTORIZACION, D_IMPORTE_TRANSACCION, SAFE_CAST(D_DIFERIMIENTO AS STRING), D_CODIGO_TRANSACCION, D_FECHA_TRANSACCION, D_FECHA_PROCESO, SUBSTRING(D_NUMERO_TARJETAHABIENTE, 1, 6) ) TOTAL GROUP BY YEAR, MONTH, D_ID_MERCHANT, D_ACCOUNT_CARDHOLDER, D_NUMBER_AUTHORIZATION, D_AMOUNT_TRANSACTION, SAFE_CAST(D_NUMBER_PROMOTION_PAYMENTS AS STRING), D_AMOUNT_EXCHANGE_FEE, D_CODE_TRANSACTION, D_BIN_ACQUIRER, D_NUMBER_ACQUIRER_REFERENCE, D_AMOUNT_CASHBACK, D_CODE_CURRENCY_DESTINATION, D_TYPE_PROMOTION_PLAN, D_DATE_FILE, DS_SOURCE, DS_LINKED_SOURCE, D_FECHA_PROCESO, KN_ACQUIRER_INTERN, D_ISSUER_BIN;"


