Query13="INSERT INTO transformed_evo_sensitive.tmp_stg_vol_log_detail_cy_citi_banamex_mx  (  etlbatchid,  etl_batch_date,  tmp_stg_vol_log_detail_cy_citi_banamex_mx_sk,  create_date_time,  update_date_time,  d_id_merchant,  d_plataforma,  procesador_grupo,  d_access_channel,  year,  month,  d_account_cardholder,  d_number_authorization,  d_amount_transaction,  d_code_response_transaction,  d_pos_entry_mode,  d_id_dispatcher,  d_bin_issuer,  d_code_result_on2,  d_type_message,  d_type_transaction_on2,  d_date_iso_transaction,  d_id_form_factor,  d_id_electronic_commerce,  d_number_terminal_transaction,  d_serial_device,  d_logical_network,  ks_platform,  kn_acquirer_intern) SELECT  CAST(${etlbatchid} AS STRING) AS etlbatchid,  CURRENT_DATE() AS etl_batch_date,  GENERATE_UUID() AS tmp_stg_vol_log_detail_cy_citi_banamex_mx_sk,  CURRENT_TIMESTAMP() AS create_date_time,  CURRENT_TIMESTAMP() AS update_date_time,  d_id_merchant,  TRIM(d_plataforma),  TRIM(procesador_grupo),  TRIM(SAFE_CAST(d_access_channel AS STRING)) AS d_access_channel,  year,  month,  TRIM(d_account_cardholder),  TRIM(d_number_authorization),  d_amount_transaction,  SAFE_CAST(d_code_response_transaction AS STRING) AS d_code_response_transaction,  TRIM(d_pos_entry_mode),  TRIM(SAFE_CAST(d_id_dispatcher AS String)) AS d_id_dispatcher,  TRIM(d_bin_issuer),  TRIM(d_code_result_on2),  d_type_message,  d_type_transaction_on2,  d_date_iso_transaction,  TRIM(d_id_form_factor),  TRIM(d_id_electronic_commerce),  TRIM(d_number_terminal_transaction),  TRIM(d_serial_device),  TRIM(d_logical_network),  TRIM(ks_platform),  kn_acquirer_intern FROM  transformed_evo_sensitive.tmp_stg_vol_log_detail_citi_banamex_mx WHERE  DATE_TRUNC(d_date_iso_transaction, MONTH) >= DATE_TRUNC(DATE_SUB(CURRENT_DATE(), INTERVAL 26 DAY), MONTH);"


Query14="TRUNCATE TABLE transformed_evo_sensitive.tmp_stg_vol_log_detail_activity_citi_banamex_mx; INSERT INTO transformed_evo_sensitive.tmp_stg_vol_log_detail_activity_citi_banamex_mx SELECT etlbatchid, etl_batch_date, tmp_stg_vol_log_detail_cy_citi_banamex_mx_sk, create_date_time, update_date_time, D_ID_MERCHANT, D_PLATAFORMA AS KS_PLATFORM, 'Activity' AS DS_SOURCE, 2 AS DN_SOURCE_ORDER, YEAR, MONTH, D_ACCOUNT_CARDHOLDER, D_NUMBER_AUTHORIZATION, D_AMOUNT_TRANSACTION, PROCESADOR_GRUPO, D_ACCESS_CHANNEL, D_CODE_RESPONSE_TRANSACTION, D_POS_ENTRY_MODE, D_ID_DISPATCHER, D_BIN_ISSUER, D_CODE_RESULT_ON2, D_TYPE_MESSAGE, D_TYPE_TRANSACTION_ON2, D_DATE_ISO_TRANSACTION, D_ID_FORM_FACTOR, D_ID_ELECTRONIC_COMMERCE, D_NUMBER_TERMINAL_TRANSACTION, D_SERIAL_DEVICE, D_LOGICAL_NETWORK, KN_ACQUIRER_INTERN FROM ( SELECT DISTINCT TRIM(etlbatchid) AS etlbatchid, etl_batch_date, tmp_stg_vol_log_detail_cy_citi_banamex_mx_sk, create_date_time, update_date_time, YEAR, MONTH, D_ACCOUNT_CARDHOLDER, D_NUMBER_AUTHORIZATION, D_AMOUNT_TRANSACTION, PROCESADOR_GRUPO, CAST(D_ACCESS_CHANNEL AS INT64) AS D_ACCESS_CHANNEL, D_CODE_RESPONSE_TRANSACTION, D_POS_ENTRY_MODE, CAST(D_ID_DISPATCHER AS INT64) AS D_ID_DISPATCHER, D_BIN_ISSUER, D_CODE_RESULT_ON2, D_TYPE_MESSAGE, D_TYPE_TRANSACTION_ON2, D_DATE_ISO_TRANSACTION, D_ID_FORM_FACTOR, D_ID_ELECTRONIC_COMMERCE, D_NUMBER_TERMINAL_TRANSACTION, D_SERIAL_DEVICE, D_LOGICAL_NETWORK, D_ID_MERCHANT, CASE WHEN KS_PLATFORM IS NULL THEN CASE D_ACCESS_CHANNEL WHEN '02' THEN '084' WHEN '08' THEN '052' WHEN '09' THEN '084' ELSE '020' END ELSE KS_PLATFORM END AS D_PLATAFORMA, KN_ACQUIRER_INTERN FROM transformed_evo_sensitive.tmp_stg_vol_log_detail_cy_citi_banamex_mx Activity ) ACTIVITY WHERE D_ID_MERCHANT IS NOT NULL;"


Query15="TRUNCATE TABLE transformed_evo_sensitive.tmp_stg_vol_log_detail_activity_platform_citi_banamex_mx; INSERT INTO transformed_evo_sensitive.tmp_stg_vol_log_detail_activity_platform_citi_banamex_mx SELECT TRIM(etlbatchid), etl_batch_date, tmp_stg_vol_log_detail_activity_citi_banamex_mx_sk as tmp_stg_vol_log_detail_activity_platform_citi_banamex_mx_sk, create_date_time, update_date_time, log.d_id_merchant, TRIM(mids.ks_platform_concat), TRIM(log.ks_platform_anterior), TRIM(log.procesador_grupo), log.d_access_channel, TRIM(log.d_account_cardholder), TRIM(log.d_number_authorization), log.d_amount_transaction, TRIM(log.d_code_response_transaction), TRIM(log.d_pos_entry_mode), log.d_id_dispatcher, TRIM(log.d_bin_issuer), TRIM(d_code_result_on2), d_type_message, d_type_transaction_on2, d_date_iso_transaction, TRIM(d_id_form_factor), TRIM(d_id_electronic_commerce), TRIM(d_number_terminal_transaction), TRIM(d_serial_device), TRIM(d_logical_network), kn_acquirer_intern FROM ( SELECT etlbatchid, etl_batch_date, tmp_stg_vol_log_detail_activity_citi_banamex_mx_sk, create_date_time, update_date_time, lt.d_id_merchant, procesador_grupo, d_access_channel, d_account_cardholder, d_number_authorization, d_amount_transaction, d_code_response_transaction, d_pos_entry_mode, d_id_dispatcher, d_bin_issuer, d_code_result_on2, d_type_message, d_type_transaction_on2, d_date_iso_transaction, d_id_form_factor, d_id_electronic_commerce, d_number_terminal_transaction, d_serial_device, d_logical_network, ks_platform AS ks_platform_anterior, kn_acquirer_intern FROM transformed_evo_sensitive.tmp_stg_vol_log_detail_activity_citi_banamex_mx AS lt ) log LEFT JOIN ( SELECT d_id_merchant, RTRIM( max(CASE rno WHEN 1 THEN ks_platform ELSE '' END) || ',' || max(CASE rno WHEN 2 THEN ks_platform ELSE '' END) || ',' || max(CASE rno WHEN 3 THEN ks_platform ELSE '' END) || ',' || max(CASE rno WHEN 4 THEN ks_platform ELSE '' END) || ',' || max(CASE rno WHEN 5 THEN ks_platform ELSE '' END) || ',' || max(CASE rno WHEN 6 THEN ks_platform ELSE '' END), ',') AS ks_platform_concat FROM ( SELECT d_id_merchant, ks_platform, row_number() OVER (PARTITION BY d_id_merchant ORDER BY ks_platform) AS rno FROM ( SELECT d_id_merchant, TRIM(SAFE_CAST(ks_platform AS string)) AS ks_platform FROM transformed_evo.tmp_stg_mid_platform_citi_banamex_mx WHERE dn_source_order = 3 GROUP BY d_id_merchant,TRIM(SAFE_CAST(ks_platform AS string)) ) plataforma GROUP BY d_id_merchant, ks_platform ) mid_platform_concat GROUP BY d_id_merchant ) mids ON mids.d_id_merchant = log.d_id_merchant;"


