Query22="INSERT INTO consumption_evo_bi.f_volume_platform_monthly_detail_citi_banamex_mx ( etlbatchid, etl_batch_date, f_volume_platform_monthly_detail_citi_banamex_mx_sk, create_date_time, update_date_time, kn_merchant, kn_date, kn_date_date, ks_platform, mf_vol_total, mf_vol_cred, mf_vol_deb, mf_vol_int, mf_vol_prepay, mn_trx_total, mn_trx_cred, mn_trx_deb, mn_trx_int, mn_trx_prepay, dn_code_response_transaction, ds_pos_entry_mode, ks_dispatcher, ks_bin, dn_number_promotion_payments, ds_code_result_on2, dn_type_message, dn_type_transaction_on2, ds_access_channel, ds_group_processor, ds_form_factor, ds_electronic_commerce_parameter, ds_account_cardholder, dn_amount_exchange_fee, ds_code_transaction, ds_bin_acquirer, ds_number_acquirer_reference, dn_amount_cashback, ds_code_currency_destination, dn_type_promotion_plan, dd_date_file, d_number_terminal_transaction, d_serial_device, d_logical_network, ds_source, ds_linked_source) SELECT CAST(${etlbatchid} AS STRING) AS etlbatchid, CURRENT_DATE() AS etl_batch_date, GENERATE_UUID() AS f_volume_platform_monthly_detail_citi_banamex_mx_sk, CURRENT_TIMESTAMP() AS create_date_time, CURRENT_TIMESTAMP() AS update_date_time, SAFE_CAST(TSVE.D_ID_MERCHANT AS INTEGER) AS KN_MERCHANT, SAFE_CAST( SAFE_CAST(YEAR AS STRING) || LPAD(SAFE_CAST(MONTH AS STRING), 2, '0') || '01' AS INT64) AS KN_DATE, PARSE_DATE( '%Y%m%d', SAFE_CAST(YEAR AS STRING) || LPAD(SAFE_CAST(MONTH AS STRING), 2, '0') || '01') AS KN_DATE_DATE, IFNULL( TSVLD.KS_PLATFORM, CASE WHEN TSVE.DS_SOURCE = 'V_AMEX_SETTLEMENT' THEN '020' ELSE CASE WHEN TSVE.IMPORTE_TOTAL < 0 THEN '171' ELSE '170' END END) AS KS_PLATFORM, SUM(TSVE.IMPORTE_TOTAL) AS MF_VOL_TOTAL, SUM(CASE WHEN DS_NATURE = 'CRÉDITO' THEN TSVE.IMPORTE_TOTAL ELSE 0 END) AS MF_VOL_CRED, SUM(CASE WHEN DS_NATURE = 'DÉBITO' THEN TSVE.IMPORTE_TOTAL ELSE 0 END) AS MF_VOL_DEB, SUM(CASE WHEN DBN.KS_BIN IS NULL THEN TSVE.IMPORTE_TOTAL ELSE 0 END) AS MF_VOL_INT, SUM(CASE WHEN DS_NATURE = 'PREPAGO' THEN TSVE.IMPORTE_TOTAL ELSE